import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';


@Component({
  selector: 'app-userdetail',
  templateUrl: './userdetail.component.html',
  styleUrls: ['./userdetail.component.scss']
})
export class UserdetailComponent {

  posts: any;
  data:any;

  user: User;
  user_id: string;

  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService
    ){
    this.route.params.subscribe((p: any) => {
      this.user_id = p.user_id;
      this.getUserDetails();
    })
  }

  ngOnInit() {
    
  }


  getUserDetails() {
    const subscription = this.api.getUserDetails(this.user_id).subscribe((response: any) => {
      subscription.unsubscribe();
      const u : any = response.user
      this.user = {
        first_name: u.first_name,
        last_name: u.last_name,
        nick_name: u.nick_name,
        email: u.email,
        phone: u.phone,
        phone_code: u.phone_code,
        is_blocked: u.is_blocked,
        user_addresses: u.user_addresses.map((address: any) => {
          return {
            address_line_1: address.address_line_1,
            address_line_2: address.address_line_2,
            address_name: address.address_name,
            postal_code: address.postal_code,
            city: address.city,
            state: address.state.state_name,
            country: address.state.country.country_name
          }
        })
      }
    })
  }

  blockUser() {
    const sub = this.api.blockUser(this.user_id).subscribe(() => {
      sub.unsubscribe();
      this.toastr.success("User blocked successfully")
      this.getUserDetails()
    })
  }

  unblockUser() {
    const sub = this.api.unblockUser(this.user_id).subscribe(() => {
      sub.unsubscribe();
      this.toastr.success("User unblocked successfully")
      this.getUserDetails()
    })
  }


}


interface UserAddress {
  address_line_1 : string;
  address_line_2 : string;
  address_name : string;
  city : string;
  postal_code : string;
  state : string;
  country : string;
}



interface User {
  first_name : string;
  last_name : string;
  nick_name : string;
  email : string;
  phone_code : string;
  phone : string;
  user_addresses : [UserAddress];
  is_blocked: boolean;
}