import { AfterViewInit, Component, ViewChild, OnInit } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { HttpClient } from '@angular/common/http';
import { MatSort } from '@angular/material/sort';
import { catchError, delay, map, merge, of, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';

@Component({
  selector: 'app-userlist',
  templateUrl: './userlist.component.html',
  styleUrls: ['./userlist.component.scss']
})
export class UserlistComponent {

  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['user_id', 'first_name', 'Email', 'Phone',  'Action'];
  data : User[] = [];
  resultsLength = 0;
  sortBy: string = 'user_id'

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

  ngOnInit(): void {

  }
  
  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', ]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.listUsers(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction).subscribe((data: any) => {
        this.isLoadingResults = false;
        if (data === null) {
          return [];
        }
  
        this.resultsLength = data.total_count;
        this.data = data.users.map(user => {
          return {
            user_id: user.user_id,
            full_name: user.full_name,
            email: user.email,
            phone_number: user.phone_code + '-' + user.phone,
          }
        });
      })
    })

  }

 
  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.listUsers(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.users.map(user => {
            return {
              user_id: user.user_id,
              full_name: user.full_name,
              email: user.email,
              phone_number: user.phone_code + '-' + user.phone,
            }
          });
        }),
      )
      .subscribe(data => this.data = data);
  }

}


export interface User {
  user_id: string;
  full_name: string;
  email: string;
  phone_number: string;
}





